1	/********************************************************************
2	 * This file includes functions to build fabric dependent bitstream
3	 *******************************************************************/
4	#include <algorithm>
5	#include <cmath>
6	#include <string>
7	
8	/* Headers from vtrutil library */
9	#include "vtr_assert.h"
10	#include "vtr_log.h"
11	#include "vtr_time.h"
12	
13	/* Headers from openfpgautil library */
14	#include "bitstream_manager_utils.h"
15	#include "build_fabric_bitstream.h"
16	#include "build_fabric_bitstream_memory_bank.h"
17	#include "decoder_library_utils.h"
18	#include "openfpga_decode.h"
