33	 * Note that it is guarentee that the instance name in module manager is
34	 * consistent with the block names in bitstream manager
35	 * We use this link to reorganize the bitstream in the sequence of memories as
36	 *we stored in the configurable_children() and configurable_child_instances() of
37	 *each module of module manager
38	 *
39	 * In such configuration organization, each memory cell has an unique index.
40	 * Using this index, we can infer the address codes for both BL and WL decoders.
41	 * Note that, we must get the number of BLs and WLs before using this function!
42	 *******************************************************************/
43	static void rec_build_module_fabric_dependent_ql_memory_bank_regional_bitstream(
44	  const BitstreamManager& bitstream_manager, const ConfigBlockId& parent_block,
45	  const ModuleManager& module_manager, const ModuleId& top_module,
46	  const ModuleId& parent_module, const ConfigRegionId& config_region,
47	  const ConfigProtocol& config_protocol, const CircuitLibrary& circuit_lib,
48	  const CircuitModelId& sram_model, const size_t& bl_addr_size,
49	  const size_t& wl_addr_size, size_t& num_bls_cur_tile,
50	  const std::map<int, size_t>& bl_start_index_per_tile,
51	  size_t& num_wls_cur_tile,
52	  const std::map<int, size_t>& wl_start_index_per_tile,
53	  vtr::Point<int>& tile_coord, std::map<vtr::Point<int>, size_t>& cur_mem_index,
54	  FabricBitstream& fabric_bitstream,
55	  const FabricBitRegionId& fabric_bitstream_region) {
56	  /* Depth-first search: if we have any children in the parent_block,
57	   * we dive to the next level first!
58	   */
59	  if (0 < bitstream_manager.block_children(parent_block).size()) {
60	    /* For top module:
61	     *   - Use regional configurable children
62	     *   - we will skip the two decoders at the end of the configurable children
63	     * list
64	     */
65	    if (parent_module == top_module) {
66	      std::vector<ModuleId> configurable_children =
67	        module_manager.region_configurable_children(parent_module,
68	                                                    config_region);
69	
70	      VTR_ASSERT(2 <= configurable_children.size());
71	      size_t num_config_child_to_skip =
72	        estimate_num_configurable_children_to_skip_by_config_protocol(
73	          config_protocol, configurable_children.size());
74	      size_t num_configurable_children =
75	        configurable_children.size() - num_config_child_to_skip;
76	
77	      /* Early exit if there is no configurable children */
78	      if (0 == num_configurable_children) {
79	        /* Ensure that there should be no configuration bits in the parent block
80	         */
81	        VTR_ASSERT(0 == bitstream_manager.block_bits(parent_block).size());
82	        return;
83	      }
84	
85	      for (size_t child_id = 0; child_id < num_configurable_children;
86	           ++child_id) {
87	        ModuleId child_module = configurable_children[child_id];
88	        size_t child_instance =
89	          module_manager.region_configurable_child_instances(
90	            parent_module, config_region)[child_id];
91	
92	        tile_coord = module_manager.region_configurable_child_coordinates(
93	          parent_module, config_region)[child_id];
94	        num_bls_cur_tile = find_module_ql_memory_bank_num_blwls(
95	          module_manager, child_module, circuit_lib, sram_model,
96	          CONFIG_MEM_QL_MEMORY_BANK, CIRCUIT_MODEL_PORT_BL);
97	        num_wls_cur_tile = find_module_ql_memory_bank_num_blwls(
98	          module_manager, child_module, circuit_lib, sram_model,
99	          CONFIG_MEM_QL_MEMORY_BANK, CIRCUIT_MODEL_PORT_WL);
100	
101	        /* Get the instance name and ensure it is not empty */
102	        std::string instance_name = module_manager.instance_name(
103	          parent_module, child_module, child_instance);
104	
105	        /* Find the child block that matches the instance name! */
106	        ConfigBlockId child_block =
107	          bitstream_manager.find_child_block(parent_block, instance_name);
108	        /* We must have one valid block id! */
109	        VTR_ASSERT(true == bitstream_manager.valid_block_id(child_block));
110	
111	        /* Go recursively */
112	        rec_build_module_fabric_dependent_ql_memory_bank_regional_bitstream(
113	          bitstream_manager, child_block, module_manager, top_module,
114	          child_module, config_region, config_protocol, circuit_lib, sram_model,
115	          bl_addr_size, wl_addr_size, num_bls_cur_tile, bl_start_index_per_tile,
116	          num_wls_cur_tile, wl_start_index_per_tile, tile_coord, cur_mem_index,
117	          fabric_bitstream, fabric_bitstream_region);
118	      }
119	    } else {
120	      VTR_ASSERT(parent_module != top_module);
121	      /* For other modules:
122	       *   - Use configurable children directly
123	       *   - no need to exclude decoders as they are not there
124	       */
125	      std::vector<ModuleId> configurable_children =
126	        module_manager.configurable_children(
127	          parent_module, ModuleManager::e_config_child_type::PHYSICAL);
128	
129	      size_t num_configurable_children = configurable_children.size();
130	
131	      /* Early exit if there is no configurable children */
132	      if (0 == num_configurable_children) {
133	        /* Ensure that there should be no configuration bits in the parent block
134	         */
135	        VTR_ASSERT(0 == bitstream_manager.block_bits(parent_block).size());
136	        return;
137	      }
138	
139	      for (size_t child_id = 0; child_id < num_configurable_children;
140	           ++child_id) {
141	        ModuleId child_module = configurable_children[child_id];
142	        size_t child_instance = module_manager.configurable_child_instances(
143	          parent_module,
144	          ModuleManager::e_config_child_type::PHYSICAL)[child_id];
145	
146	        /* Get the instance name and ensure it is not empty */
147	        std::string instance_name = module_manager.instance_name(
148	          parent_module, child_module, child_instance);
149	
150	        /* Find the child block that matches the instance name! */
151	        ConfigBlockId child_block =
152	          bitstream_manager.find_child_block(parent_block, instance_name);
153	        /* We must have one valid block id! */
154	        VTR_ASSERT(true == bitstream_manager.valid_block_id(child_block));
155	
156	        /* Go recursively */
157	        rec_build_module_fabric_dependent_ql_memory_bank_regional_bitstream(
158	          bitstream_manager, child_block, module_manager, top_module,
159	          child_module, config_region, config_protocol, circuit_lib, sram_model,
160	          bl_addr_size, wl_addr_size, num_bls_cur_tile, bl_start_index_per_tile,
161	          num_wls_cur_tile, wl_start_index_per_tile, tile_coord, cur_mem_index,
162	          fabric_bitstream, fabric_bitstream_region);
163	      }
164	    }
165	    /* Ensure that there should be no configuration bits in the parent block */
166	    VTR_ASSERT(0 == bitstream_manager.block_bits(parent_block).size());
167	
168	    return;
169	  }
170	
171	  /* Note that, reach here, it means that this is a leaf node.
172	   * We add the configuration bits to the fabric_bitstream,
173	   * And then, we can return
174	   */
175	  for (const ConfigBitId& config_bit :
176	       bitstream_manager.block_bits(parent_block)) {
177	    FabricBitId fabric_bit = fabric_bitstream.add_bit(config_bit);
178	
179	    /*
180	      If both BL and WL protocols are Flatten, we will have new way of
181	      storing information in fabric_bitstream. This will save high
182	      memory usage, as well as fast processing
183	    */
184	    /* The BL address to be decoded depends on the protocol
185	     * - flatten BLs: use 1-hot decoding
186	     * - BL decoders: fully encoded
187	     * - Shift register: use 1-hot decoding
188	     */
189	    size_t cur_bl_index = bl_start_index_per_tile.at(tile_coord.x()) +
190	                          cur_mem_index[tile_coord] % num_bls_cur_tile;
191	    if (BLWL_PROTOCOL_FLATTEN != config_protocol.bl_protocol_type() ||
192	        BLWL_PROTOCOL_FLATTEN != config_protocol.wl_protocol_type()) {
193	      // This is using old way
194	      // We only do this kind of resource wasting storing if
195	      // either protocol is not flatten
196	      std::vector<char> bl_addr_bits_vec;
197	      if (BLWL_PROTOCOL_DECODER == config_protocol.bl_protocol_type()) {
198	        bl_addr_bits_vec = itobin_charvec(cur_bl_index, bl_addr_size);
199	      } else if (BLWL_PROTOCOL_FLATTEN == config_protocol.bl_protocol_type() ||
200	                 BLWL_PROTOCOL_SHIFT_REGISTER ==
201	                   config_protocol.bl_protocol_type()) {
202	        bl_addr_bits_vec =
203	          ito1hot_charvec(cur_bl_index, bl_addr_size, DONT_CARE_CHAR);
204	      }
205	      /* Set BL address */
206	      fabric_bitstream.set_bit_bl_address(
207	        fabric_bit, bl_addr_bits_vec,
208	        BLWL_PROTOCOL_DECODER != config_protocol.bl_protocol_type());
209	    }
210	
211	    /* Find WL address */
212	    size_t cur_wl_index =
213	      wl_start_index_per_tile.at(tile_coord.y()) +
214	      std::floor(cur_mem_index[tile_coord] / num_bls_cur_tile);
215	    if (BLWL_PROTOCOL_FLATTEN != config_protocol.bl_protocol_type() ||
216	        BLWL_PROTOCOL_FLATTEN != config_protocol.wl_protocol_type()) {
217	      // This is using old way
218	      // We only do this kind of resource wasting storing if
219	      // either protocol is not flatten
220	      std::vector<char> wl_addr_bits_vec;
221	      if (BLWL_PROTOCOL_DECODER == config_protocol.wl_protocol_type()) {
222	        wl_addr_bits_vec = itobin_charvec(cur_wl_index, wl_addr_size);
223	      } else if (BLWL_PROTOCOL_FLATTEN == config_protocol.wl_protocol_type() ||
224	                 BLWL_PROTOCOL_SHIFT_REGISTER ==
225	                   config_protocol.wl_protocol_type()) {
226	        wl_addr_bits_vec = ito1hot_charvec(cur_wl_index, wl_addr_size);
227	      }
228	      /* Set WL address */
229	      fabric_bitstream.set_bit_wl_address(
230	        fabric_bit, wl_addr_bits_vec,
231	        BLWL_PROTOCOL_DECODER != config_protocol.wl_protocol_type());
232	    }
233	    if (BLWL_PROTOCOL_FLATTEN == config_protocol.bl_protocol_type() &&
234	        BLWL_PROTOCOL_FLATTEN == config_protocol.wl_protocol_type()) {
235	      // New way of storing information in compact way
236	      // Only for Flatten protocol (can easily support shift register as well)
237	      // Need to understand decoder to better assessment
238	      fabric_bitstream.set_memory_bank_info(
239	        fabric_bit, fabric_bitstream_region, cur_bl_index, cur_wl_index,
240	        bl_addr_size, wl_addr_size, bitstream_manager.bit_value(config_bit));
241	    }
242	
243	    /* Set data input */
244	    fabric_bitstream.set_bit_din(fabric_bit,
245	                                 bitstream_manager.bit_value(config_bit));
246	
247	    /* Add the bit to the region */
248	    fabric_bitstream.add_bit_to_region(fabric_bitstream_region, fabric_bit);
249	
250	    /* Increase the memory index */
251	    cur_mem_index[tile_coord]++;
252	  }
253	}
254	
255	/********************************************************************
256	 * Main function to build a fabric-dependent bitstream
257	 * by considering the QuickLogic memory banks
258	 *******************************************************************/
259	void build_module_fabric_dependent_bitstream_ql_memory_bank(
260	  const ConfigProtocol& config_protocol, const CircuitLibrary& circuit_lib,
261	  const BitstreamManager& bitstream_manager, const ConfigBlockId& top_block,
262	  const ModuleManager& module_manager, const ModuleId& top_module,
263	  FabricBitstream& fabric_bitstream) {
264	  /* Ensure we are in the correct type of configuration protocol*/
265	  VTR_ASSERT(config_protocol.type() == CONFIG_MEM_QL_MEMORY_BANK);
266	
267	  /* For different BL control protocol, the address ports are different
268	   * - flatten BLs: the address port should be raw BL ports at top-level module.
269	   *                Due to each configuration region has separated BLs, the
270	   * address port should be the one with largest size
271	   * - BL decoders: the address port should be the BL address port at top-level
272	   * module
273	   * - Shift register: the address port size will be calculated by the total
274	   * number of unique BLs per child module in each configuration region Due to
275	   * each configuration region has separated BLs, the address port should be the
276	   * one with largest size
277	   */
278	  ModulePortId bl_addr_port;
279	  BasicPort bl_addr_port_info;
280	  if (BLWL_PROTOCOL_DECODER == config_protocol.bl_protocol_type()) {
281	    bl_addr_port = module_manager.find_module_port(
282	      top_module, std::string(DECODER_BL_ADDRESS_PORT_NAME));
283	    bl_addr_port_info = module_manager.module_port(top_module, bl_addr_port);
284	  } else if (BLWL_PROTOCOL_FLATTEN == config_protocol.bl_protocol_type()) {
285	    for (const ConfigRegionId& config_region :
286	         module_manager.regions(top_module)) {
287	      ModulePortId temp_bl_addr_port = module_manager.find_module_port(
288	        top_module, generate_regional_blwl_port_name(
289	                      std::string(MEMORY_BL_PORT_NAME), config_region));
290	      BasicPort temp_bl_addr_port_info =
291	        module_manager.module_port(top_module, temp_bl_addr_port);
292	      if (!bl_addr_port || (temp_bl_addr_port_info.get_width() >
293	                            bl_addr_port_info.get_width())) {
294	        bl_addr_port = temp_bl_addr_port;
295	        bl_addr_port_info = temp_bl_addr_port_info;
296	      }
297	    }
298	  } else {
299	    VTR_ASSERT(BLWL_PROTOCOL_SHIFT_REGISTER ==
300	               config_protocol.bl_protocol_type());
301	    bl_addr_port_info.set_width(1); /* Deposit minimum width */
302	    for (const ConfigRegionId& config_region :
303	         module_manager.regions(top_module)) {
304	      size_t num_bls = compute_memory_bank_regional_num_bls(
305	        module_manager, top_module, config_region, circuit_lib,
306	        config_protocol.memory_model());
307	      bl_addr_port_info.set_width(
308	        std::max(num_bls, bl_addr_port_info.get_width()));
309	    }
310	  }
311	
312	  /* For different WL control protocol, the address ports are different
313	   * - flatten WLs: the address port should be raw WL ports at top-level module.
314	   *                Due to each configuration region has separated WLs, the
315	   * address port should be the one with largest size
316	   * - WL decoders: the address port should be the WL address port at top-level
317	   * module
318	   * - Shift register: the address port size will be calculated by the total
319	   * number of unique WLs per child module in each configuration region Due to
320	   * each configuration region has separated WLs, the address port should be the
321	   * one with largest size
322	   */
323	  ModulePortId wl_addr_port;
324	  BasicPort wl_addr_port_info;
325	  if (BLWL_PROTOCOL_DECODER == config_protocol.wl_protocol_type()) {
326	    wl_addr_port = module_manager.find_module_port(
327	      top_module, std::string(DECODER_WL_ADDRESS_PORT_NAME));
328	    wl_addr_port_info = module_manager.module_port(top_module, wl_addr_port);
329	  } else if (BLWL_PROTOCOL_FLATTEN == config_protocol.wl_protocol_type()) {
330	    for (const ConfigRegionId& config_region :
331	         module_manager.regions(top_module)) {
332	      ModulePortId temp_wl_addr_port = module_manager.find_module_port(
333	        top_module, generate_regional_blwl_port_name(
334	                      std::string(MEMORY_WL_PORT_NAME), config_region));
335	      BasicPort temp_wl_addr_port_info =
336	        module_manager.module_port(top_module, temp_wl_addr_port);
337	      if (!wl_addr_port || (temp_wl_addr_port_info.get_width() >
338	                            wl_addr_port_info.get_width())) {
339	        wl_addr_port = temp_wl_addr_port;
340	        wl_addr_port_info = temp_wl_addr_port_info;
341	      }
342	    }
343	  } else {
344	    VTR_ASSERT(BLWL_PROTOCOL_SHIFT_REGISTER ==
345	               config_protocol.wl_protocol_type());
346	    wl_addr_port_info.set_width(1); /* Deposit minimum width */
347	    for (const ConfigRegionId& config_region :
348	         module_manager.regions(top_module)) {
349	      size_t num_wls = compute_memory_bank_regional_num_wls(
350	        module_manager, top_module, config_region, circuit_lib,
351	        config_protocol.memory_model());
352	      wl_addr_port_info.set_width(
353	        std::max(num_wls, wl_addr_port_info.get_width()));
354	    }
355	  }
356	
357	  /* Reserve bits before build-up */
358	  fabric_bitstream.set_use_address(true);
359	  fabric_bitstream.set_use_wl_address(true);
360	  fabric_bitstream.set_bl_address_length(bl_addr_port_info.get_width());
361	  fabric_bitstream.set_wl_address_length(wl_addr_port_info.get_width());
362	  fabric_bitstream.reserve_bits(bitstream_manager.num_bits());
363	
364	  /* Build bitstreams by region */
365	  for (const ConfigRegionId& config_region :
366	       module_manager.regions(top_module)) {
367	    /* Find port information for local BL and WL decoder in this region */
368	    std::vector<ModuleId> configurable_children =
369	      module_manager.region_configurable_children(top_module, config_region);
370	    VTR_ASSERT(2 <= configurable_children.size());
371	
372	    /* Build the bitstream for all the blocks in this region */
373	    FabricBitRegionId fabric_bitstream_region = fabric_bitstream.add_region();
374	
375	    /* Find the BL/WL port (different region may have different sizes of BL/WLs)
376	     */
377	    ModulePortId cur_bl_addr_port;
378	    BasicPort cur_bl_addr_port_info;
379	    if (BLWL_PROTOCOL_DECODER == config_protocol.bl_protocol_type()) {
380	      cur_bl_addr_port = module_manager.find_module_port(
381	        top_module, std::string(DECODER_BL_ADDRESS_PORT_NAME));
382	      cur_bl_addr_port_info =
383	        module_manager.module_port(top_module, cur_bl_addr_port);
384	    } else if (BLWL_PROTOCOL_FLATTEN == config_protocol.bl_protocol_type()) {
385	      cur_bl_addr_port = module_manager.find_module_port(
386	        top_module, generate_regional_blwl_port_name(
387	                      std::string(MEMORY_BL_PORT_NAME), config_region));
388	      cur_bl_addr_port_info =
389	        module_manager.module_port(top_module, cur_bl_addr_port);
390	    } else {
391	      VTR_ASSERT(BLWL_PROTOCOL_SHIFT_REGISTER ==
392	                 config_protocol.bl_protocol_type());
393	      cur_bl_addr_port_info.set_width(compute_memory_bank_regional_num_bls(
394	        module_manager, top_module, config_region, circuit_lib,
395	        config_protocol.memory_model()));
396	    }
397	
398	    ModulePortId cur_wl_addr_port;
399	    BasicPort cur_wl_addr_port_info;
400	    if (BLWL_PROTOCOL_DECODER == config_protocol.wl_protocol_type()) {
401	      cur_wl_addr_port = module_manager.find_module_port(
402	        top_module, std::string(DECODER_WL_ADDRESS_PORT_NAME));
403	      cur_wl_addr_port_info =
404	        module_manager.module_port(top_module, cur_wl_addr_port);
405	    } else if (BLWL_PROTOCOL_FLATTEN == config_protocol.wl_protocol_type()) {
406	      cur_wl_addr_port = module_manager.find_module_port(
407	        top_module, generate_regional_blwl_port_name(
408	                      std::string(MEMORY_WL_PORT_NAME), config_region));
409	      cur_wl_addr_port_info =
410	        module_manager.module_port(top_module, cur_wl_addr_port);
411	    } else {
412	      VTR_ASSERT(BLWL_PROTOCOL_SHIFT_REGISTER ==
413	                 config_protocol.wl_protocol_type());
414	      cur_wl_addr_port_info.set_width(compute_memory_bank_regional_num_wls(
415	        module_manager, top_module, config_region, circuit_lib,
416	        config_protocol.memory_model()));
417	    }
418	
419	    /**************************************************************
420	     * Precompute the BLs and WLs distribution across the FPGA fabric
421	     * The distribution is a matrix which contains the starting index of BL/WL
422	     * for each column or row
423	     */
424	    std::pair<int, int> child_x_range =
425	      compute_memory_bank_regional_configurable_child_x_range(
426	        module_manager, top_module, config_region);
427	    std::pair<int, int> child_y_range =
428	      compute_memory_bank_regional_configurable_child_y_range(
429	        module_manager, top_module, config_region);
430	
431	    std::map<int, size_t> num_bls_per_tile =
432	      compute_memory_bank_regional_bitline_numbers_per_tile(
433	        module_manager, top_module, config_region, circuit_lib,
434	        config_protocol.memory_model());
435	    std::map<int, size_t> num_wls_per_tile =
436	      compute_memory_bank_regional_wordline_numbers_per_tile(
437	        module_manager, top_module, config_region, circuit_lib,
438	        config_protocol.memory_model());
439	
440	    std::map<int, size_t> bl_start_index_per_tile =
441	      compute_memory_bank_regional_blwl_start_index_per_tile(child_x_range,
442	                                                             num_bls_per_tile);
443	    std::map<int, size_t> wl_start_index_per_tile =
444	      compute_memory_bank_regional_blwl_start_index_per_tile(child_y_range,
445	                                                             num_wls_per_tile);
446	
447	    vtr::Point<int> temp_coord(-1, -1);
448	    std::map<vtr::Point<int>, size_t> cur_mem_index;
449	    size_t temp_num_bls_cur_tile = 0;
450	    size_t temp_num_wls_cur_tile = 0;
451	
452	    rec_build_module_fabric_dependent_ql_memory_bank_regional_bitstream(
453	      bitstream_manager, top_block, module_manager, top_module, top_module,
454	      config_region, config_protocol, circuit_lib,
455	      config_protocol.memory_model(), cur_bl_addr_port_info.get_width(),
456	      cur_wl_addr_port_info.get_width(), temp_num_bls_cur_tile,
457	      bl_start_index_per_tile, temp_num_wls_cur_tile, wl_start_index_per_tile,
458	      temp_coord, cur_mem_index, fabric_bitstream, fabric_bitstream_region);
459	  }
460	}
461	
462	} /* end namespace openfpga */
