MemoryBankShiftRegisterFabricBitstreamWordId
MemoryBankShiftRegisterFabricBitstream::create_word() {
  /* Create a new id*/
  MemoryBankShiftRegisterFabricBitstreamWordId word_id =
    MemoryBankShiftRegisterFabricBitstreamWordId(bitstream_word_ids_.size());
