14	/**************************************************
15	 * FabricBitstreamMemoryBank
16	 *************************************************/
17	void FabricBitstreamMemoryBank::add_bit(const fabric_size_t& bit_id,
18	                                        const fabric_size_t& region_id,
19	                                        const fabric_size_t& bl,
20	                                        const fabric_size_t& wl,
21	                                        const fabric_size_t& bl_addr_size,
22	                                        const fabric_size_t& wl_addr_size,
23	                                        bool bit) {
24	  // Fabric Bit is added in sequential manner and each bit is unique
25	  VTR_ASSERT((size_t)(bit_id) == fabric_bit_datas.size());
26	  // Region is added in sequntial manner but it is not unique from fabric bit
27	  // perspective
28	  VTR_ASSERT((size_t)(region_id) <= blwl_lengths.size());
29	  if ((size_t)(region_id) == blwl_lengths.size()) {
30	    // Add if this is first time
31	    blwl_lengths.push_back(fabric_blwl_length(bl_addr_size, wl_addr_size));
32	  } else {
33	    // Otherwise if the region had been added, it must always be consistent
34	    VTR_ASSERT(blwl_lengths[region_id].bl == bl_addr_size);
35	    VTR_ASSERT(blwl_lengths[region_id].wl == wl_addr_size);
36	  }
37	  // The BL/WL index must be within respective length
38	  VTR_ASSERT(bl < blwl_lengths[region_id].bl);
39	  VTR_ASSERT(wl < blwl_lengths[region_id].wl);
40	  // We might not need this at all to track the raw data
41	  // But since it does not use a lot of memory, tracking for good
42	  fabric_bit_datas.push_back(fabric_bit_data((fabric_size_t)(size_t)(region_id),
43	                                             (fabric_size_t)(bl),
44	                                             (fabric_size_t)(wl), bit));
45	  // This is real compact data
46	  VTR_ASSERT(datas.size() == masks.size());
47	  while ((size_t)(region_id) >= datas.size()) {
48	    datas.emplace_back();
49	    masks.emplace_back();
50	  }
51	  VTR_ASSERT(datas[region_id].size() == masks[region_id].size());
52	  while ((size_t)(wl) >= datas[region_id].size()) {
53	    datas[region_id].push_back(std::vector<uint8_t>((bl_addr_size + 7) / 8, 0));
54	    masks[region_id].push_back(std::vector<uint8_t>((bl_addr_size + 7) / 8, 0));
55	  }
56	  // Same uniqie config bit cannot be set twice
57	  VTR_ASSERT((masks[region_id][wl][bl >> 3] & (1 << (bl & 7))) == 0);
58	  if (bit) {
59	    // Mark the data value if bit (or din) is true
60	    datas[region_id][wl][bl >> 3] |= (1 << (bl & 7));
61	  }
62	  // Mark the mask to indicate we had used this bit
63	  masks[region_id][wl][bl >> 3] |= (1 << (bl & 7));
64	}
