66	void FabricBitstreamMemoryBank::fast_configuration(
67	  const bool& fast, const bool& bit_value_to_skip) {
68	  for (auto& wls : wls_to_skip) {
69	    wls.clear();
70	  }
71	  wls_to_skip.clear();
72	  for (size_t region = 0; region < datas.size(); region++) {
73	    wls_to_skip.emplace_back();
74	    if (fast) {
75	      for (fabric_size_t wl = 0; wl < blwl_lengths[region].wl; wl++) {
76	        VTR_ASSERT((size_t)(wl) < datas[region].size());
77	        bool skip_wl = true;
78	        for (fabric_size_t bl = 0; bl < blwl_lengths[region].bl && skip_wl;
79	             bl++) {
80	          // Only check the bit that being used (marked in the mask),
81	          // otherwise it is just a don't care, we can skip
82	          if (masks[region][wl][bl >> 3] & (1 << (bl & 7))) {
83	            if (datas[region][wl][bl >> 3] & (1 << (bl & 7))) {
84	              // If bit_value_to_skip=true, and yet the din (recorded in
85	              // datas) also 1, then we can skip
86	              skip_wl = bit_value_to_skip;
87	            } else {
88	              skip_wl = !bit_value_to_skip;
89	            }
90	          }
91	        }
92	        if (skip_wl) {
93	          // Record down that for this region, we will skip this WL
94	          wls_to_skip[region].push_back(wl);
95	        }
96	      }
97	    }
98	  }
99	}
100	
101	fabric_size_t FabricBitstreamMemoryBank::get_longest_effective_wl_count()
102	  const {
103	  // This function check effective WL count
104	  // Where effective WL is the WL that we want to program after considering
105	  // fast configuration from all the region, it return the longest
106	  fabric_size_t longest_wl = 0;
107	  for (size_t region = 0; region < datas.size(); region++) {
108	    VTR_ASSERT((size_t)(region) < wls_to_skip.size());
109	    fabric_size_t current_wl =
110	      (fabric_size_t)(datas[region].size() - wls_to_skip[region].size());
111	    if (current_wl > longest_wl) {
112	      longest_wl = current_wl;
113	    }
114	  }
115	  return longest_wl;
116	}
