118	fabric_size_t FabricBitstreamMemoryBank::get_total_bl_addr_size() const {
119	  // Simply total up all the BL addr size
120	  fabric_size_t bl = 0;
121	  for (size_t region = 0; region < datas.size(); region++) {
122	    bl += blwl_lengths[region].bl;
123	  }
124	  return bl;
125	}
