466	uint64_t FabricBitstream::encode_address_1bits(
467	  const std::vector<char>& address) const {
468	  /* Convert all the 'x' bit into 0 */
469	  std::vector<char> binary_address = address;
470	  for (char& bit : binary_address) {
471	    if (bit == 'x') {
472	      bit = '0';
473	    }
474	  }
475	  /* Convert the binary address to a number */
476	  return (uint64_t)bintoi_charvec(binary_address);
477	}
478	
479	uint64_t FabricBitstream::encode_address_xbits(
480	  const std::vector<char>& address) const {
481	  /* Convert all the '1' bit into 0 and Convert all the 'x' bit into 1 */
482	  std::vector<char> binary_address = address;
483	  for (char& bit : binary_address) {
484	    if (bit == '1') {
485	      bit = '0';
486	    }
487	    if (bit == 'x') {
488	      bit = '1';
489	    }
490	  }
491	  /* Convert the binary address to a number */
492	  return (uint64_t)bintoi_charvec(binary_address);
493	}
494	
495	std::vector<char> FabricBitstream::decode_address_bits(
496	  const size_t& bit1, const size_t& bitx, const size_t& addr_len) const {
497	  /* Decode the bit1 number to a binary vector */
498	  std::vector<char> ret_vec = itobin_charvec(bit1, addr_len);
499	  /* Decode the bitx number to a binary vector */
500	  std::vector<char> bitx_vec = itobin_charvec(bitx, addr_len);
501	  /* Combine the two vectors: 'x' overwrite any bit '0' and '1' */
502	  for (size_t ibit = 0; ibit < ret_vec.size(); ++ibit) {
503	    if (bitx_vec[ibit] == '1') {
504	      ret_vec[ibit] = 'x';
505	    }
506	  }
507	  return ret_vec;
508	}
