52	static int write_flatten_fabric_bitstream_to_text_file(
53	  std::fstream& fp, const BitstreamManager& bitstream_manager,
54	  const FabricBitstream& fabric_bitstream) {
55	  if (false == valid_file_stream(fp)) {
