71	 * Write the fabric bitstream fitting a configuration chain protocol
72	 * to a plain text file
73	 *
74	 * Return:
75	 *  - 0 if succeed
76	 *  - 1 if critical errors occured
77	 *******************************************************************/
78	static int write_config_chain_fabric_bitstream_to_text_file(
79	  std::fstream& fp, const bool& fast_configuration,
80	  const bool& bit_value_to_skip, const BitstreamManager& bitstream_manager,
81	  const FabricBitstream& fabric_bitstream) {
82	  int status = 0;
83	
84	  size_t regional_bitstream_max_size =
85	    find_fabric_regional_bitstream_max_size(fabric_bitstream);
86	  ConfigChainFabricBitstream regional_bitstreams =
87	    build_config_chain_fabric_bitstream_by_region(bitstream_manager,
88	                                                  fabric_bitstream);
89	
90	  /* For fast configuration, the bitstream size counts from the first bit '1' */
91	  size_t num_bits_to_skip = 0;
92	  if (true == fast_configuration) {
93	    num_bits_to_skip =
94	      find_configuration_chain_fabric_bitstream_size_to_be_skipped(
95	        fabric_bitstream, bitstream_manager, bit_value_to_skip);
96	    VTR_ASSERT(num_bits_to_skip < regional_bitstream_max_size);
97	    VTR_LOG(
98	      "Fast configuration will skip %g% (%lu/%lu) of configuration "
99	      "bitstream.\n",
100	      100. * (float)num_bits_to_skip / (float)regional_bitstream_max_size,
101	      num_bits_to_skip, regional_bitstream_max_size);
102	  }
103	
104	  /* Output bitstream size information */
105	  fp << "// Bitstream length: "
106	     << regional_bitstream_max_size - num_bits_to_skip << std::endl;
107	  fp << "// Bitstream width (LSB -> MSB): " << fabric_bitstream.num_regions()
108	     << std::endl;
109	
110	  /* Output bitstream data */
111	  for (size_t ibit = num_bits_to_skip; ibit < regional_bitstream_max_size;
112	       ++ibit) {
113	    for (const auto& region_bitstream : regional_bitstreams) {
114	      fp << region_bitstream[ibit];
115	    }
116	    if (ibit < regional_bitstream_max_size - 1) {
117	      fp << std::endl;
118	    }
119	  }
120	
121	  return status;
122	}
