202	 * Return:
203	 *  - 0 if succeed
204	 *  - 1 if critical errors occured
205	 *******************************************************************/
206	static int write_memory_bank_flatten_fabric_bitstream_to_text_file(
207	  std::fstream& fp, const bool& fast_configuration,
208	  const bool& bit_value_to_skip, const FabricBitstream& fabric_bitstream,
209	  const bool& keep_dont_care_bits) {
210	  int status = 0;
211	
212	  char dont_care_bit = '0';
213	  if (keep_dont_care_bits) {
214	    dont_care_bit = DONT_CARE_CHAR;
215	  }
216	  MemoryBankFlattenFabricBitstream fabric_bits =
217	    build_memory_bank_flatten_fabric_bitstream(
218	      fabric_bitstream, fast_configuration, bit_value_to_skip, dont_care_bit);
219	
220	  /* The address sizes and data input sizes are the same across any element,
221	   * just get it from the 1st element to save runtime
222	   */
223	  size_t bl_addr_size = fabric_bits.bl_vector_size();
224	  size_t wl_addr_size = fabric_bits.wl_vector_size();
225	
226	  /* Output information about how to intepret the bitstream */
227	  fp << "// Bitstream length: " << fabric_bits.size() << std::endl;
228	  fp << "// Bitstream width (LSB -> MSB): ";
229	  fp << "<bl_address " << bl_addr_size << " bits>";
230	  fp << "<wl_address " << wl_addr_size << " bits>";
231	  fp << std::endl;
232	
233	  for (const auto& wl_vec : fabric_bits.wl_vectors()) {
234	    /* Write BL address code */
235	    for (const auto& bl_unit : fabric_bits.bl_vector(wl_vec)) {
236	      fp << bl_unit;
237	    }
238	    /* Write WL address code */
239	    for (const auto& wl_unit : wl_vec) {
240	      fp << wl_unit;
241	    }
